150	export function getHandlePositions(
151	  shape: Shape
152	): { x: number; y: number; w: number; h: number; corner: string }[] {
153	  const hs = HANDLE_SIZE;
154	  const half = hs / 2;
155	  return [
156	    { x: shape.x - half - 2, y: shape.y - half - 2, w: hs, h: hs, corner: "nw" },
157	    { x: shape.x + shape.width - half + 2, y: shape.y - half - 2, w: hs, h: hs, corner: "ne" },
158	    { x: shape.x - half - 2, y: shape.y + shape.height - half + 2, w: hs, h: hs, corner: "sw" },
159	    {
160	      x: shape.x + shape.width - half + 2,
161	      y: shape.y + shape.height - half + 2,
162	      w: hs,
163	      h: hs,
164	      corner: "se",
165	    },
166	  ];
167	}
