219	export function hitTest(shapes: Shape[], x: number, y: number): Shape | null {
220	  // Iterate in reverse z-order (topmost first)
221	  for (let i = shapes.length - 1; i >= 0; i--) {
222	    const s = shapes[i];
223	    if (isPointInShape(s, x, y)) {
224	      return s;
225	    }
226	  }
227	  return null;
228	}
229	
230	function isPointInShape(shape: Shape, px: number, py: number): boolean {
231	  const margin = 4;
232	  switch (shape.type) {
233	    case "rectangle":
234	    case "text":
235	      return (
236	        px >= shape.x - margin &&
237	        px <= shape.x + shape.width + margin &&
238	        py >= shape.y - margin &&
239	        py <= shape.y + shape.height + margin
240	      );
241	
242	    case "ellipse": {
243	      const cx = shape.x + shape.width / 2;
244	      const cy = shape.y + shape.height / 2;
245	      const rx = Math.abs(shape.width / 2) + margin;
246	      const ry = Math.abs(shape.height / 2) + margin;
247	      if (rx === 0 || ry === 0) return false;
248	      const dx = px - cx;
249	      const dy = py - cy;
250	      return (dx * dx) / (rx * rx) + (dy * dy) / (ry * ry) <= 1;
251	    }
252	
253	    case "line": {
254	      // Check distance from point to line segment
255	      const x1 = shape.x;
256	      const y1 = shape.y;
257	      const x2 = shape.x + shape.width;
258	      const y2 = shape.y + shape.height;
259	      const dist = distToSegment(px, py, x1, y1, x2, y2);
260	      return dist <= shape.strokeWidth / 2 + margin + 4;
261	    }
262	
263	    default:
264	      return false;
265	  }
266	}
267	
268	function distToSegment(
269	  px: number,
270	  py: number,
271	  x1: number,
272	  y1: number,
273	  x2: number,
274	  y2: number
275	): number {
276	  const dx = x2 - x1;
277	  const dy = y2 - y1;
278	  const lenSq = dx * dx + dy * dy;
279	  if (lenSq === 0) return Math.sqrt((px - x1) ** 2 + (py - y1) ** 2);
280	  let t = ((px - x1) * dx + (py - y1) * dy) / lenSq;
281	  t = Math.max(0, Math.min(1, t));
282	  const projX = x1 + t * dx;
283	  const projY = y1 + t * dy;
284	  return Math.sqrt((px - projX) ** 2 + (py - projY) ** 2);
285	}
286	
287	export function hitTestHandle(
288	  shape: Shape,
289	  x: number,
290	  y: number
291	): string | null {
292	  const handles = getHandlePositions(shape);
293	  for (const h of handles) {
294	    if (x >= h.x && x <= h.x + h.w && y >= h.y && y <= h.y + h.h) {
295	      return h.corner;
296	    }
297	  }
298	  return null;
299	}
